use std::io::{self, Read};
fn is_number(s: &str) -> bool { let bytes = s.as_bytes(); let mut seen_digit = false; let mut seen_dot = false; let mut seen_exp = false; let mut digit_after_exp = true; for i in 0..bytes.len() { let ch = bytes[i] as char; if ch.is_ascii_digit() { seen_digit = true; if seen_exp { digit_after_exp = true; } } else if ch == '+' || ch == '-' { if i != 0 && bytes[i - 1] as char != 'e' && bytes[i - 1] as char != 'E' { return false; } } else if ch == '.' { if seen_dot || seen_exp { return false; } seen_dot = true; } else if ch == 'e' || ch == 'E' { if seen_exp || !seen_digit { return false; } seen_exp = true; digit_after_exp = false; } else { return false; } } seen_digit && digit_after_exp }
fn main() { let mut input = String::new(); io::stdin().read_to_string(&mut input).unwrap(); let lines: Vec<&str> = input.lines().collect(); if !lines.is_empty() { let t: usize = lines[0].trim().parse().unwrap(); let mut out = Vec::new(); for i in 0..t { out.push(if is_number(lines[i + 1]) { "true" } else { "false" }); } print!("{}", out.join("\n")); } }
